def merge_ranges(pairs):
    pairs.sort(key=lambda x: x[0])
    merged = [pairs[0]]

    for pair in pairs[1:]:
        last = merged[-1]
        if last[1] >= pair[0]:
            last[1] = max(last[1], pair[1])
        else:
